func testTotalCorrectAllMatch() {
    var sheet = AnswerSheet(title: "test")
    for i in 1...200 {
        let choice = TOEICTemplate.choiceLabels(for: i)[0]
        sheet.setAnswer(choice, for: i)
        sheet.setCorrectAnswer(choice, for: i)
    }
    XCTAssertEqual(sheet.totalCorrect, 200)
    XCTAssertEqual(sheet.scorePercentage, 100.0, accuracy: 0.001)
}

func testTotalCorrectNoneMatch() {
    var sheet = AnswerSheet(title: "test")
    for i in 1...200 {
