func testScorePercentagePartial() {
    var sheet = AnswerSheet(title: "test")
    // 問題1〜100を正解、101〜200を不正解に設定
    for i in 1...100 {
        let choice = TOEICTemplate.choiceLabels(for: i)[0]
        sheet.setAnswer(choice, for: i)
        sheet.setCorrectAnswer(choice, for: i)
    }
    for i in 101...200 {
        let labels = TOEICTemplate.choiceLabels(for: i)
        sheet.setAnswer(labels[0], for: i)
        sheet.setCorrectAnswer(labels.count > 1 ? labels[1] : labels[0], for: i)
    }
    XCTAssertEqual(sheet.scorePercentage, 50.0, accuracy: 0.001)
}

