func testAnswerSheetEncodeDecode() throws {
    var original = AnswerSheet(title: "往復テスト")
    original.setAnswer("A", for: 1)
    original.setAnswer("B", for: 100)
    original.setCorrectAnswer("C", for: 1)
    original.elapsedSeconds = 120
    original.status = .answered

    let encoder = JSONEncoder()
    let decoder = JSONDecoder()
    let data = try encoder.encode(original)
    let decoded = try decoder.decode(AnswerSheet.self, from: data)

    XCTAssertEqual(decoded.id, original.id)
    XCTAssertEqual(decoded.title, original.title)
    XCTAssertEqual(decoded.userAnswers[0], "A")
    XCTAssertEqual(decoded.userAnswers[99], "B")
    XCTAssertEqual(decoded.correctAnswers[0], "C")
    XCTAssertEqual(decoded.elapsedSeconds, 120)
    XCTAssertEqual(decoded.status, .answered)
}

func testAnswerSheetArrayEncodeDecode() throws {
    var sheets: [AnswerSheet] = []
    for i in 1...3 {
        var sheet = AnswerSheet(title: "Sheet \(i)")
        sheet.setAnswer("A", for: i)
        sheets.append(sheet)
    }

    let encoder = JSONEncoder()
    let decoder = JSONDecoder()
    let data = try encoder.encode(sheets)
    let decoded = try decoder.decode([AnswerSheet].self, from: data)

    XCTAssertEqual(decoded.count, 3)
    for i in 0..<3 {
        XCTAssertEqual(decoded[i].title, "Sheet \(i + 1)")
    }
}

func testSheetStatusCodable() throws {
    let statuses: [SheetStatus] = [.answering, .answered, .scoring, .scored]
    let encoder = JSONEncoder()
    let decoder = JSONDecoder()

    for status in statuses {
        let data = try encoder.encode(status)
        let decoded = try decoder.decode(SheetStatus.self, from: data)
        XCTAssertEqual(decoded, status)
    }
}

func testNilAnswersPreservedAfterDecode() throws {
    var sheet = AnswerSheet(title: "test")
    // 奇数問のみ回答
    for i in stride(from: 1, through: 200, by: 2) {
        sheet.setAnswer("A", for: i)
    }

    let data = try JSONEncoder().encode(sheet)
    let decoded = try JSONDecoder().decode(AnswerSheet.self, from: data)

    XCTAssertEqual(decoded.answeredCount, 100)
    XCTAssertNotNil(decoded.userAnswers[0])   // 問題1
    XCTAssertNil(decoded.userAnswers[1])       // 問題2
    XCTAssertNotNil(decoded.userAnswers[198]) // 問題199
    XCTAssertNil(decoded.userAnswers[199])     // 問題200
}

