func testPartRangesContiguous() {
    let ranges = TOEICTemplate.partRanges
    XCTAssertEqual(ranges.first?.range.lowerBound, 1)
    XCTAssertEqual(ranges.last?.range.upperBound, 200)

    for i in 1..<ranges.count {
        let prev = ranges[i - 1].range.upperBound
        let next = ranges[i].range.lowerBound
        XCTAssertEqual(prev + 1, next, "パート\(i)と\(i+1)の範囲が連続していない")
    }
}

